  1→/**
  2→ * ExceptionApprovalDashboard Component
  3→ *
  4→ * Dashboard for ADMIN/SECCHAMPION to review and approve/reject exception requests
  5→ *
  6→ * Features:
  7→ * - Summary statistics cards (pending count, approvals, rejections)
  8→ * - Pending requests table sorted by oldest first
  9→ * - View details, approve, and reject actions
 10→ * - Pagination support (20/50/100 items per page)
 11→ * - Empty state handling
 12→ *
 13→ * Feature: 031-vuln-exception-approval
 14→ * User Story 3: ADMIN Approval Dashboard (P1)
 15→ * Reference: spec.md FR-018 to FR-023
 16→ */
 17→
 18→import React, { useState, useEffect } from 'react';
 19→import {
 20→  getPendingRequests,
 21→  approveRequest,
 22→  rejectRequest,
 23→  getStatistics,
 24→  exportToExcel,
 25→  type VulnerabilityExceptionRequestDto,
 26→  type PagedResponse,
 27→  type ExceptionStatisticsDto
 28→} from '../services/exceptionRequestService';
 29→import ExceptionStatusBadge from './ExceptionStatusBadge';
 30→import ApprovalDetailModal from './ApprovalDetailModal';
 31→import CveLink from './CveLink';
 32→
 33→const ExceptionApprovalDashboard: React.FC = () => {
 34→  // Data states
 35→  const [pendingRequests, setPendingRequests] = useState<PagedResponse<VulnerabilityExceptionRequestDto> | null>(null);
 36→  const [loading, setLoading] = useState(true);
 37→  const [error, setError] = useState<string | null>(null);
 38→  const [successMessage, setSuccessMessage] = useState<string | null>(null);
 39→
 40→  // Pagination states
 41→  const [currentPage, setCurrentPage] = useState(0);
 42→  const [pageSize, setPageSize] = useState(20);
 43→
 44→  // Modal states
 45→  const [showDetailModal, setShowDetailModal] = useState(false);
 46→  const [selectedRequestId, setSelectedRequestId] = useState<number | null>(null);
 47→
 48→  // Action states
 49→  const [approvingId, setApprovingId] = useState<number | null>(null);
 50→  const [rejectingId, setRejectingId] = useState<number | null>(null);
 51→
 52→  // Statistics states
 53→  const [showStatistics, setShowStatistics] = useState(false);
 54→  const [statisticsData, setStatisticsData] = useState<ExceptionStatisticsDto | null>(null);
 55→  const [statisticsDateRange, setStatisticsDateRange] = useState('30days');
 56→  const [statisticsLoading, setStatisticsLoading] = useState(false);
 57→  const [statisticsError, setStatisticsError] = useState<string | null>(null);
 58→
 59→  // Export state
 60→  const [exporting, setExporting] = useState(false);
 61→
 62→  useEffect(() => {
 63→    fetchPendingRequests();
 64→  }, [currentPage, pageSize]);
 65→
 66→  useEffect(() => {
 67→    if (showStatistics) {
 68→      fetchStatistics();
 69→    }
 70→  }, [showStatistics, statisticsDateRange]);
 71→
 72→  const fetchPendingRequests = async () => {
 73→    try {
 74→      setLoading(true);
 75→      setError(null);
 76→
 77→      const data = await getPendingRequests(currentPage, pageSize);
 78→      setPendingRequests(data);
 79→    } catch (err) {
 80→      const errorMessage = err instanceof Error ? err.message : 'Failed to load pending requests';
 81→      setError(errorMessage);
 82→    } finally {
 83→      setLoading(false);
 84→    }
 85→  };
 86→
 87→  const handlePageSizeChange = (size: number) => {
 88→    setPageSize(size);
 89→    setCurrentPage(0); // Reset to first page when page size changes
 90→  };
 91→
 92→  const handleViewDetails = (requestId: number) => {
 93→    setSelectedRequestId(requestId);
 94→    setShowDetailModal(true);
 95→  };
 96→
 97→  const handleCloseDetailModal = () => {
 98→    setShowDetailModal(false);
 99→    setSelectedRequestId(null);
100→  };
101→
102→  const handleQuickApprove = async (request: VulnerabilityExceptionRequestDto) => {
103→    if (!confirm(`Approve exception request for ${request.vulnerabilityCve || 'vulnerability'} on ${request.assetName}?`)) {
104→      return;
105→    }
106→
107→    try {
108→      setApprovingId(request.id);
109→      await approveRequest(request.id);
110→
111→      setSuccessMessage(`Exception request #${request.id} approved successfully.`);
112→
113→      // Auto-dismiss success message after 5 seconds
114→      setTimeout(() => {
115→        setSuccessMessage(null);
116→      }, 5000);
117→
118→      // Refresh pending list
119→      fetchPendingRequests();
120→    } catch (err) {
121→      const errorMessage = err instanceof Error ? err.message : 'Failed to approve request';
122→      setError(errorMessage);
123→    } finally {
124→      setApprovingId(null);
125→    }
126→  };
127→
128→  const handleQuickReject = (request: VulnerabilityExceptionRequestDto) => {
129→    // Open detail modal for rejection (requires comment)
130→    handleViewDetails(request.id);
131→  };
132→
133→  const handleModalApprove = () => {
134→    // Refresh data after modal approval
135→    fetchPendingRequests();
136→    handleCloseDetailModal();
137→  };
138→
139→  const handleModalReject = () => {
140→    // Refresh data after modal rejection
141→    fetchPendingRequests();
142→    handleCloseDetailModal();
143→  };
144→
145→  const fetchStatistics = async () => {
146→    try {
147→      setStatisticsLoading(true);
148→      setStatisticsError(null);
149→
150→      const data = await getStatistics(statisticsDateRange);
151→      setStatisticsData(data);
152→    } catch (err) {
153→      const errorMessage = err instanceof Error ? err.message : 'Failed to load statistics';
154→      setStatisticsError(errorMessage);
155→    } finally {
156→      setStatisticsLoading(false);
157→    }
158→  };
159→
160→  const handleExportToExcel = async () => {
161→    try {
162→      setExporting(true);
163→      setError(null);
164→
165→      await exportToExcel({ dateRange: statisticsDateRange });
166→
167→      setSuccessMessage('Exception requests exported successfully.');
168→      setTimeout(() => {
169→        setSuccessMessage(null);
170→      }, 5000);
171→    } catch (err) {
172→      const errorMessage = err instanceof Error ? err.message : 'Failed to export requests';
173→      setError(errorMessage);
174→    } finally {
175→      setExporting(false);
176→    }
177→  };
178→
179→  // Render loading state
180→  if (loading && !pendingRequests) {
181→    return (
182→      <div className="container-fluid p-4">
183→        <div className="d-flex justify-content-center p-5">
184→          <div className="spinner-border" role="status">
185→            <span className="visually-hidden">Loading...</span>
186→          </div>
187→        </div>
188→      </div>
189→    );
190→  }
191→
192→  // Render error state
193→  if (error && !pendingRequests) {
194→    return (
195→      <div className="container-fluid p-4">
196→        <div className="alert alert-danger" role="alert">
197→          <i className="bi bi-exclamation-triangle me-2"></i>
198→          {error}
199→        </div>
200→      </div>
201→    );
202→  }
203→
204→  const pendingCount = pendingRequests?.totalElements || 0;
205→
206→  return (
207→    <div className="container-fluid p-4">
208→      {/* Page Header */}
209→      <div className="row">
210→        <div className="col-12">
211→          <div className="d-flex justify-content-between align-items-center mb-4">
212→            <h2>
213→              <i className="bi bi-shield-check me-2"></i>
214→              Exception Approvals
215→            </h2>
216→            <div className="btn-group" role="group">
217→              <button
218→                className="btn btn-outline-success"
219→                onClick={handleExportToExcel}
220→                disabled={exporting}
221→                title="Export to Excel"
222→              >
223→                {exporting ? (
224→                  <>
225→                    <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
226→                    Exporting...
227→                  </>
228→                ) : (
229→                  <>
230→                    <i className="bi bi-file-earmark-excel me-2"></i>
231→                    Export to Excel
232→                  </>
233→                )}
234→              </button>
235→              <button
236→                className="btn btn-outline-primary"
237→                onClick={fetchPendingRequests}
238→                disabled={loading}
239→              >
240→                <i className="bi bi-arrow-clockwise me-2"></i>
241→                Refresh
242→              </button>
243→            </div>
244→          </div>
245→        </div>
246→      </div>
247→
248→      {/* Success Message */}
249→      {successMessage && (
250→        <div className="row mb-3">
251→          <div className="col-12">
252→            <div className="alert alert-success alert-dismissible fade show" role="alert">
253→              <i className="bi bi-check-circle me-2"></i>
254→              {successMessage}
255→              <button
256→                type="button"
257→                className="btn-close"
258→                onClick={() => setSuccessMessage(null)}
259→                aria-label="Close"
260→              ></button>
261→            </div>
262→          </div>
263→        </div>
264→      )}
265→
266→      {/* Error Message */}
267→      {error && pendingRequests && (
268→        <div className="row mb-3">
269→          <div className="col-12">
270→            <div className="alert alert-warning alert-dismissible fade show" role="alert">
271→              <i className="bi bi-exclamation-triangle me-2"></i>
272→              {error}
273→              <button
274→                type="button"
275→                className="btn-close"
276→                onClick={() => setError(null)}
277→                aria-label="Close"
278→              ></button>
279→            </div>
280→          </div>
281→        </div>
282→      )}
283→
284→      {/* Summary Cards */}
285→      <div className="row mb-4">
286→        <div className="col-md-4">
287→          <div className="card border-danger">
288→            <div className="card-body">
289→              <h6 className="card-subtitle mb-2 text-danger">Pending Requests</h6>
290→              <h3 className="card-title mb-0 text-danger">
291→                {pendingCount}
292→                {pendingCount > 0 && (
293→                  <span className="badge bg-danger ms-2">{pendingCount}</span>
294→                )}
295→              </h3>
296→              <p className="text-muted small mb-0 mt-2">
297→                Awaiting review
298→              </p>
299→            </div>
300→          </div>
301→        </div>
302→      </div>
303→
304→      {/* Controls */}
305→      <div className="row mb-3">
306→        <div className="col-md-4">
307→          <label htmlFor="pageSize" className="form-label">Items per Page</label>
308→          <select
309→            id="pageSize"
310→            className="form-select"
311→            value={pageSize}
312→            onChange={(e) => handlePageSizeChange(Number(e.target.value))}
313→          >
314→            <option value="20">20</option>
315→            <option value="50">50</option>
316→            <option value="100">100</option>
317→          </select>
318→        </div>
319→      </div>
320→
321→      {/* Pending Requests Table */}
322→      <div className="row">
323→        <div className="col-12">
324→          <div className="card">
325→            <div className="card-body">
326→              <h5 className="card-title">
327→                Pending Requests
328→                {pendingCount > 0 && (
329→                  <span className="badge bg-danger ms-2">{pendingCount}</span>
330→                )}
331→              </h5>
332→
333→              {pendingRequests && pendingRequests.content.length === 0 ? (
334→                <div className="text-center py-5">
335→                  <i className="bi bi-check-circle display-1 text-success"></i>
336→                  <p className="text-muted mt-3">
337→                    No pending requests. Great job staying on top of security governance!
338→                  </p>
339→                </div>
340→              ) : (
341→                <>
342→                  <div className="table-responsive">
343→                    <table className="table table-striped table-hover">
344→                      <thead>
345→                        <tr>
346→                          <th>CVE ID</th>
347→                          <th>Asset</th>
348→                          <th>Requested By</th>
349→                          <th>Scope</th>
350→                          <th>Reason</th>
351→                          <th>Submitted</th>
352→                          <th>Days Pending</th>
353→                          <th>Actions</th>
354→                        </tr>
355→                      </thead>
356→                      <tbody>
357→                        {pendingRequests?.content.map((request) => {
358→                          const submittedDate = new Date(request.createdAt);
359→                          const now = new Date();
360→                          const daysPending = Math.floor((now.getTime() - submittedDate.getTime()) / (1000 * 60 * 60 * 24));
361→
362→                          return (
363→                            <tr key={request.id}>
364→                              <td>
365→                                <CveLink cveId={request.vulnerabilityCve} />
366→                              </td>
367→                              <td>{request.assetName}</td>
368→                              <td>{request.requestedByUsername}</td>
369→                              <td>
370→                                {request.scope === 'SINGLE_VULNERABILITY' ? (
371→                                  <span className="badge bg-info text-dark">
372→                                    <i className="bi bi-bullseye me-1"></i>
373→                                    Single
374→                                  </span>
375→                                ) : (
376→                                  <span className="badge bg-primary">
377→                                    <i className="bi bi-grid-3x3 me-1"></i>
378→                                    Pattern
379→                                  </span>
380→                                )}
381→                              </td>
382→                              <td style={{ maxWidth: '300px' }}>
383→                                <div
384→                                  style={{
385→                                    overflow: 'hidden',
386→                                    textOverflow: 'ellipsis',
387→                                    whiteSpace: 'nowrap'
388→                                  }}
389→                                  title={request.reason}
390→                                >
391→                                  {request.reason.substring(0, 100)}
392→                                  {request.reason.length > 100 && '...'}
393→                                </div>
394→                              </td>
395→                              <td>
396→                                {submittedDate.toLocaleDateString()}
397→                              </td>
398→                              <td>
399→                                <span className={`badge ${daysPending > 7 ? 'bg-danger' : daysPending > 3 ? 'bg-warning text-dark' : 'bg-secondary'}`}>
400→                                  {daysPending} days
401→                                </span>
402→                              </td>
403→                              <td>
404→                                <div className="btn-group btn-group-sm" role="group">
405→                                  <button
406→                                    className="btn btn-outline-secondary"
407→                                    onClick={() => handleViewDetails(request.id)}
408→                                    title="View details"
409→                                  >
410→                                    <i className="bi bi-eye"></i>
411→                                  </button>
412→                                  <button
413→                                    className="btn btn-outline-success"
414→                                    onClick={() => handleQuickApprove(request)}
415→                                    disabled={approvingId === request.id}
416→                                    title="Quick approve"
417→                                  >
418→                                    {approvingId === request.id ? (
419→                                      <span className="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>
420→                                    ) : (
421→                                      <i className="bi bi-check-circle"></i>
422→                                    )}
423→                                  </button>
424→                                  <button
425→                                    className="btn btn-outline-danger"
426→                                    onClick={() => handleQuickReject(request)}
427→                                    title="Reject (requires comment)"
428→                                  >
429→                                    <i className="bi bi-x-circle"></i>
430→                                  </button>
431→                                </div>
432→                              </td>
433→                            </tr>
434→                          );
435→                        })}
436→                      </tbody>
437→                    </table>
438→                  </div>
439→
440→                  {/* Pagination */}
441→                  {pendingRequests && pendingRequests.totalPages > 1 && (
442→                    <div className="d-flex justify-content-between align-items-center mt-3">
443→                      <div className="text-muted">
444→                        Showing {currentPage * pageSize + 1} to {Math.min((currentPage + 1) * pageSize, pendingRequests.totalElements)} of {pendingRequests.totalElements} requests
445→                      </div>
446→                      <nav aria-label="Request pagination">
447→                        <ul className="pagination mb-0">
448→                          <li className={`page-item ${currentPage === 0 ? 'disabled' : ''}`}>
449→                            <button
450→                              className="page-link"
451→                              onClick={() => setCurrentPage(currentPage - 1)}
452→                              disabled={currentPage === 0}
453→                              aria-label="Previous"
454→                            >
455→                              <span aria-hidden="true">&laquo;</span>
456→                            </button>
457→                          </li>
458→                          {Array.from({ length: pendingRequests.totalPages }, (_, i) => i).map((page) => (
459→                            <li key={page} className={`page-item ${currentPage === page ? 'active' : ''}`}>
460→                              <button
461→                                className="page-link"
462→                                onClick={() => setCurrentPage(page)}
463→                              >
464→                                {page + 1}
465→                              </button>
466→                            </li>
467→                          ))}
468→                          <li className={`page-item ${currentPage === pendingRequests.totalPages - 1 ? 'disabled' : ''}`}>
469→                            <button
470→                              className="page-link"
471→                              onClick={() => setCurrentPage(currentPage + 1)}
472→                              disabled={currentPage === pendingRequests.totalPages - 1}
473→                              aria-label="Next"
474→                            >
475→                              <span aria-hidden="true">&raquo;</span>
476→                            </button>
477→                          </li>
478→                        </ul>
479→                      </nav>
480→                      <div className="text-muted">
481→                        Page {currentPage + 1} of {pendingRequests.totalPages}
482→                      </div>
483→                    </div>
484→                  )}
485→                </>
486→              )}
487→            </div>
488→          </div>
489→        </div>
490→      </div>
491→
492→      {/* Statistics Section */}
493→      <div className="row mt-4">
494→        <div className="col-12">
495→          <div className="card">
496→            <div className="card-header" style={{ cursor: 'pointer' }} onClick={() => setShowStatistics(!showStatistics)}>
497→              <div className="d-flex justify-content-between align-items-center">
498→                <h5 className="mb-0">
499→                  <i className="bi bi-bar-chart me-2"></i>
500→                  Analytics & Reporting
501→                </h5>
502→                <i className={`bi ${showStatistics ? 'bi-chevron-up' : 'bi-chevron-down'}`}></i>
503→              </div>
504→            </div>
505→
506→            {showStatistics && (
507→              <div className="card-body">
508→                {/* Date Range Selector */}
509→                <div className="row mb-4">
510→                  <div className="col-md-4">
511→                    <label htmlFor="statsDateRange" className="form-label">Time Period</label>
512→                    <select
513→                      id="statsDateRange"
514→                      className="form-select"
515→                      value={statisticsDateRange}
516→                      onChange={(e) => setStatisticsDateRange(e.target.value)}
517→                    >
518→                      <option value="7days">Last 7 Days</option>
519→                      <option value="30days">Last 30 Days</option>
520→                      <option value="90days">Last 90 Days</option>
521→                      <option value="alltime">All Time</option>
522→                    </select>
523→                  </div>
524→                </div>
525→
526→                {/* Statistics Error */}
527→                {statisticsError && (
528→                  <div className="alert alert-warning" role="alert">
529→                    <i className="bi bi-exclamation-triangle me-2"></i>
530→                    {statisticsError}
531→                  </div>
532→                )}
533→
534→                {/* Statistics Loading */}
535→                {statisticsLoading ? (
536→                  <div className="d-flex justify-content-center p-5">
537→                    <div className="spinner-border" role="status">
538→                      <span className="visually-hidden">Loading statistics...</span>
539→                    </div>
540→                  </div>
541→                ) : statisticsData ? (
542→                  <>
543→                    {/* Metrics Cards */}
544→                    <div className="row mb-4">
545→                      {/* Total Requests */}
546→                      <div className="col-md-3">
547→                        <div className="card border-primary">
548→                          <div className="card-body">
549→                            <h6 className="card-subtitle mb-2 text-primary">Total Requests</h6>
550→                            <h3 className="card-title mb-0 text-primary">{statisticsData.totalRequests}</h3>
551→                          </div>
552→                        </div>
553→                      </div>
554→
555→                      {/* Approval Rate */}
556→                      <div className="col-md-3">
557→                        <div className="card border-success">
558→                          <div className="card-body">
559→                            <h6 className="card-subtitle mb-2 text-success">Approval Rate</h6>
560→                            <h3 className="card-title mb-0 text-success">
561→                              {statisticsData.approvalRatePercent !== null
562→                                ? `${statisticsData.approvalRatePercent.toFixed(1)}%`
563→                                : 'N/A'}
564→                            </h3>
565→                          </div>
566→                        </div>
567→                      </div>
568→
569→                      {/* Average Approval Time */}
570→                      <div className="col-md-3">
571→                        <div className="card border-info">
572→                          <div className="card-body">
573→                            <h6 className="card-subtitle mb-2 text-info">Avg Approval Time</h6>
574→                            <h3 className="card-title mb-0 text-info">
575→                              {statisticsData.averageApprovalTimeHours !== null
576→                                ? `${statisticsData.averageApprovalTimeHours.toFixed(1)}h`
577→                                : 'N/A'}
578→                            </h3>
579→                          </div>
580→                        </div>
581→                      </div>
582→
583→                      {/* Requests by Status */}
584→                      <div className="col-md-3">
585→                        <div className="card border-secondary">
586→                          <div className="card-body">
587→                            <h6 className="card-subtitle mb-2 text-secondary">By Status</h6>
588→                            <div className="small">
589→                              {Object.entries(statisticsData.requestsByStatus).map(([status, count]) => (
590→                                <div key={status} className="d-flex justify-content-between">
591→                                  <span>{status}:</span>
592→                                  <strong>{count}</strong>
593→                                </div>
594→                              ))}
595→                            </div>
596→                          </div>
597→                        </div>
598→                      </div>
599→                    </div>
600→
601→                    {/* Top Requesters and Top CVEs */}
602→                    <div className="row">
603→                      {/* Top Requesters */}
604→                      <div className="col-md-6">
605→                        <div className="card">
606→                          <div className="card-body">
607→                            <h6 className="card-title">Top Requesters</h6>
608→                            {statisticsData.topRequesters.length > 0 ? (
609→                              <table className="table table-sm">
610→                                <thead>
611→                                  <tr>
612→                                    <th>Username</th>
613→                                    <th className="text-end">Requests</th>
614→                                  </tr>
615→                                </thead>
616→                                <tbody>
617→                                  {statisticsData.topRequesters.map((requester, idx) => (
618→                                    <tr key={idx}>
619→                                      <td>{requester.username}</td>
620→                                      <td className="text-end">{requester.count}</td>
621→                                    </tr>
622→                                  ))}
623→                                </tbody>
624→                              </table>
625→                            ) : (
626→                              <p className="text-muted">No data available</p>
627→                            )}
628→                          </div>
629→                        </div>
630→                      </div>
631→
632→                      {/* Top CVEs */}
633→                      <div className="col-md-6">
634→                        <div className="card">
635→                          <div className="card-body">
636→                            <h6 className="card-title">Top CVEs</h6>
637→                            {statisticsData.topCVEs.length > 0 ? (
638→                              <table className="table table-sm">
639→                                <thead>
640→                                  <tr>
641→                                    <th>CVE ID</th>
642→                                    <th className="text-end">Requests</th>
643→                                  </tr>
644→                                </thead>
645→                                <tbody>
646→                                  {statisticsData.topCVEs.map((cve, idx) => (
647→                                    <tr key={idx}>
648→                                      <td><CveLink cveId={cve.cveId} /></td>
649→                                      <td className="text-end">{cve.count}</td>
650→                                    </tr>
651→                                  ))}
652→                                </tbody>
653→                              </table>
654→                            ) : (
655→                              <p className="text-muted">No data available</p>
