196→                                                                        <small className="text-muted">all systems</small>
197→                                                                    </>
198→                                                                )}
199→                                                            </>
200→                                                        ) : (
201→                                                            <code>{exception.targetValue}</code>
202→                                                        )}
203→                                                    </td>
204→                                                    <td>
205→                                                        {exception.affectedVulnerabilityCount !== undefined && exception.affectedVulnerabilityCount !== null ? (
206→                                                            <span 
