218→                                                        ) : (
219→                                                            <span className="text-muted">
220→                                                                <i className="bi bi-dash"></i>
221→                                                            </span>
222→                                                        )}
223→                                                    </td>
224→                                                    <td>
225→                                                        {new Date(exception.expirationDate).toLocaleString()}
226→                                                    </td>
227→                                                    <td style={{ maxWidth: '300px', overflow: 'hidden', textOverflow: 'ellipsis' }}>
228→                                                        {exception.reason}
229→                                                    </td>
230→                                                    <td>{exception.createdBy}</td>
231→                                                    <td>
232→                                                        {getStatusBadge(exception.expirationDate)}
233→                                                    </td>
234→                                                    <td>
235→                                                        <div className="btn-group" role="group">
236→                                                            <button
237→                                                                onClick={() => handleEditClick(exception)}
238→                                                                className="btn btn-sm btn-outline-primary"
239→                                                                title="Edit exception"
240→                                                            >
241→                                                                <i className="bi bi-pencil"></i>
242→                                                            </button>
243→                                                            <button
244→                                                                onClick={() => handleDelete(exception.id)}
