247→                                                            >
248→                                                                <i className="bi bi-trash"></i>
249→                                                            </button>
250→                                                        </div>
251→                                                    </td>
252→                                                </tr>
253→                                            ))}
254→                                        </tbody>
255→                                    </table>
256→                                </div>
257→                            )}
258→                        </div>
259→                    </div>
260→                </div>
261→            </div>
262→
263→            {/* Back to Home button */}
264→            <div className="row mt-4">
