  1→/**
  2→ * Exception Request Service
  3→ *
  4→ * Handles API calls for vulnerability exception request management
  5→ *
  6→ * Feature: 031-vuln-exception-approval
  7→ * User Story 1: Regular User Requests Exception (P1)
  8→ */
  9→
 10→import { authenticatedGet, authenticatedPost, authenticatedDelete } from '../utils/auth';
 11→
 12→/**
 13→ * Exception request status values
 14→ */
 15→export type ExceptionRequestStatus = 'PENDING' | 'APPROVED' | 'REJECTED' | 'EXPIRED' | 'CANCELLED';
 16→
 17→/**
 18→ * Exception scope values
 19→ */
 20→export type ExceptionScope = 'SINGLE_VULNERABILITY' | 'CVE_PATTERN';
 21→
 22→/**
 23→ * DTO for creating an exception request
 24→ */
 25→export interface CreateExceptionRequestDto {
 26→  vulnerabilityId: number;
 27→  scope: ExceptionScope;
 28→  reason: string;
 29→  expirationDate: string; // ISO 8601 datetime string
 30→}
 31→
 32→/**
 33→ * Full exception request DTO from API
 34→ */
 35→export interface VulnerabilityExceptionRequestDto {
 36→  id: number;
 37→  vulnerabilityId: number;
 38→  vulnerabilityCve: string | null;
 39→  assetId: number;
 40→  assetName: string;
 41→  assetIp: string | null;
 42→  requestedByUserId: number;
 43→  requestedByUsername: string;
 44→  scope: ExceptionScope;
 45→  reason: string;
 46→  expirationDate: string;
 47→  status: ExceptionRequestStatus;
 48→  autoApproved: boolean;
 49→  reviewedByUserId: number | null;
 50→  reviewedByUsername: string | null;
 51→  reviewDate: string | null;
 52→  reviewComment: string | null;
 53→  createdAt: string;
 54→  updatedAt: string;
 55→  version: number;
 56→}
 57→
 58→/**
 59→ * Summary statistics for user's exception requests
 60→ */
 61→export interface ExceptionRequestSummaryDto {
 62→  totalRequests: number;
 63→  pendingCount: number;
 64→  approvedCount: number;
 65→  rejectedCount: number;
 66→  expiredCount: number;
 67→  cancelledCount: number;
 68→}
 69→
 70→/**
 71→ * Paginated response wrapper
 72→ */
 73→export interface PagedResponse<T> {
 74→  content: T[];
 75→  totalElements: number;
 76→  totalPages: number;
 77→  size: number;
 78→  number: number;
 79→}
 80→
 81→/**
 82→ * Create a new exception request
 83→ *
 84→ * @param dto Request data with vulnerability ID, scope, reason, and expiration date
 85→ * @returns Created exception request
 86→ * @throws Error on 400 (validation), 401 (unauthorized), 409 (duplicate), 500 (server error)
 87→ */
 88→export async function createRequest(dto: CreateExceptionRequestDto): Promise<VulnerabilityExceptionRequestDto> {
 89→  const response = await authenticatedPost('/api/vulnerability-exception-requests', dto);
 90→
 91→  if (response.ok) {
 92→    return await response.json();
 93→  }
 94→
 95→  // Handle error responses
 96→  if (response.status === 400) {
 97→    const error = await response.json();
 98→    throw new Error(error.error || 'Invalid request data. Check reason length (50-2048 chars) and expiration date (must be in future).');
 99→  }
100→
101→  if (response.status === 401) {
102→    throw new Error('Unauthorized. Please login again.');
103→  }
104→
105→  if (response.status === 404) {
106→    const error = await response.json();
107→    throw new Error(error.error || 'Vulnerability not found.');
108→  }
109→
110→  if (response.status === 409) {
111→    const error = await response.json();
112→    throw new Error(error.error || 'An active exception request already exists for this vulnerability.');
113→  }
114→
115→  if (response.status === 500) {
116→    const error = await response.json();
117→    throw new Error(error.error || 'Failed to create exception request.');
118→  }
119→
120→  throw new Error(`Failed to create exception request: ${response.status}`);
121→}
122→
123→/**
124→ * Get current user's exception requests with optional filtering and pagination
125→ *
126→ * @param status Optional status filter (PENDING, APPROVED, REJECTED, EXPIRED, CANCELLED)
127→ * @param page Page number (0-indexed)
128→ * @param size Page size (20, 50, or 100)
129→ * @returns Paginated list of exception requests
130→ * @throws Error on 401 (unauthorized), 500 (server error)
131→ */
132→export async function getMyRequests(
133→  status?: ExceptionRequestStatus,
134→  page: number = 0,
135→  size: number = 20
136→): Promise<PagedResponse<VulnerabilityExceptionRequestDto>> {
137→  const params = new URLSearchParams();
138→  if (status) {
139→    params.append('status', status);
140→  }
141→  params.append('page', page.toString());
142→  params.append('size', size.toString());
143→
144→  const url = `/api/vulnerability-exception-requests/my?${params.toString()}`;
145→  const response = await authenticatedGet(url);
146→
147→  if (response.ok) {
148→    return await response.json();
149→  }
150→
151→  // Handle error responses
152→  if (response.status === 401) {
153→    throw new Error('Unauthorized. Please login again.');
154→  }
155→
156→  if (response.status === 500) {
157→    const error = await response.json();
158→    throw new Error(error.error || 'Failed to fetch exception requests.');
159→  }
160→
161→  throw new Error(`Failed to fetch exception requests: ${response.status}`);
162→}
163→
164→/**
165→ * Get summary statistics for current user's exception requests
166→ *
167→ * @returns Summary with counts by status
168→ * @throws Error on 401 (unauthorized), 500 (server error)
169→ */
170→export async function getMySummary(): Promise<ExceptionRequestSummaryDto> {
171→  const response = await authenticatedGet('/api/vulnerability-exception-requests/my/summary');
172→
173→  if (response.ok) {
174→    return await response.json();
175→  }
176→
177→  // Handle error responses
178→  if (response.status === 401) {
179→    throw new Error('Unauthorized. Please login again.');
180→  }
181→
182→  if (response.status === 500) {
183→    const error = await response.json();
184→    throw new Error(error.error || 'Failed to fetch request summary.');
185→  }
186→
187→  throw new Error(`Failed to fetch request summary: ${response.status}`);
188→}
189→
190→/**
191→ * Get exception request by ID
192→ *
193→ * @param id Request ID
194→ * @returns Exception request details
195→ * @throws Error on 401 (unauthorized), 403 (forbidden), 404 (not found), 500 (server error)
196→ */
197→export async function getRequestById(id: number): Promise<VulnerabilityExceptionRequestDto> {
198→  const response = await authenticatedGet(`/api/vulnerability-exception-requests/${id}`);
199→
200→  if (response.ok) {
201→    return await response.json();
202→  }
203→
204→  // Handle error responses
205→  if (response.status === 401) {
206→    throw new Error('Unauthorized. Please login again.');
207→  }
208→
209→  if (response.status === 403) {
210→    throw new Error('You do not have permission to view this request.');
211→  }
212→
213→  if (response.status === 404) {
214→    throw new Error('Exception request not found.');
215→  }
216→
217→  if (response.status === 500) {
218→    const error = await response.json();
219→    throw new Error(error.error || 'Failed to fetch exception request.');
220→  }
221→
222→  throw new Error(`Failed to fetch exception request: ${response.status}`);
223→}
224→
225→/**
226→ * Cancel an exception request (requester only, PENDING status only)
227→ *
228→ * @param id Request ID
229→ * @returns void on success
230→ * @throws Error on 400 (invalid status), 401 (unauthorized), 403 (not owner), 404 (not found), 500 (server error)
231→ */
232→export async function cancelRequest(id: number): Promise<void> {
233→  const response = await authenticatedDelete(`/api/vulnerability-exception-requests/${id}`);
234→
235→  if (response.status === 204) {
236→    return; // Success - no content
237→  }
238→
239→  // Handle error responses
240→  if (response.status === 400) {
241→    const error = await response.json();
242→    throw new Error(error.error || 'Cannot cancel this request. Only PENDING requests can be cancelled.');
243→  }
244→
245→  if (response.status === 401) {
246→    throw new Error('Unauthorized. Please login again.');
247→  }
248→
249→  if (response.status === 403) {
250→    throw new Error('You do not have permission to cancel this request. Only the requester can cancel their own requests.');
251→  }
252→
253→  if (response.status === 404) {
254→    throw new Error('Exception request not found.');
255→  }
256→
257→  if (response.status === 500) {
258→    const error = await response.json();
259→    throw new Error(error.error || 'Failed to cancel exception request.');
260→  }
261→
262→  throw new Error(`Failed to cancel exception request: ${response.status}`);
263→}
264→
265→/**
266→ * Get pending exception requests (ADMIN/SECCHAMPION only)
267→ *
268→ * @param page Page number (0-indexed)
269→ * @param size Page size (20, 50, or 100)
270→ * @returns Paginated list of pending requests sorted by oldest first
271→ * @throws Error on 401 (unauthorized), 403 (forbidden), 500 (server error)
272→ */
273→export async function getPendingRequests(
274→  page: number = 0,
275→  size: number = 20
276→): Promise<PagedResponse<VulnerabilityExceptionRequestDto>> {
277→  const params = new URLSearchParams();
278→  params.append('page', page.toString());
279→  params.append('size', size.toString());
280→
281→  const url = `/api/vulnerability-exception-requests/pending?${params.toString()}`;
