516→ * @returns void - triggers browser download
517→ * @throws Error on 401 (unauthorized), 403 (forbidden), 500 (server error)
518→ */
519→export async function exportToExcel(filters?: ExportFilters): Promise<void> {
520→  const params = new URLSearchParams();
521→  if (filters?.status) {
522→    params.append('status', filters.status);
523→  }
524→  if (filters?.dateRange) {
525→    params.append('dateRange', filters.dateRange);
526→  }
527→  if (filters?.requesterId) {
528→    params.append('requesterId', filters.requesterId.toString());
529→  }
530→  if (filters?.reviewerId) {
531→    params.append('reviewerId', filters.reviewerId.toString());
