472→/**
473→ * Export vulnerabilities with progress tracking
474→ * Feature: Vulnerability Export Performance Optimization - Background Job Pattern
475→ *
476→ * This is the main function to use for exporting. It:
477→ * 1. Starts the export job
478→ * 2. Polls for progress (calls onProgress callback)
479→ * 3. Downloads the file when complete
480→ *
481→ * @param onProgress Optional callback for progress updates
482→ * @returns Promise that resolves when download completes
483→ */
484→export async function exportVulnerabilitiesServerSide(
485→    onProgress?: (job: ExportJob) => void
486→): Promise<void> {
487→    // Start the export job
488→    const startResponse = await startVulnerabilityExport();
489→    const jobId = startResponse.jobId;
490→
491→    // Poll for status
492→    const pollInterval = 2000; // 2 seconds
493→    const maxPolls = 300; // 10 minutes max
494→    let polls = 0;
495→
496→    while (polls < maxPolls) {
497→        const job = await getExportJobStatus(jobId);
498→
499→        // Call progress callback
500→        if (onProgress) {
501→            onProgress(job);
502→        }
503→
504→        // Check if done
505→        if (job.status === 'COMPLETED') {
506→            // Download the file
507→            await downloadExportFile(jobId);
508→            return;
509→        }
510→
511→        if (job.status === 'FAILED') {
512→            throw new Error(job.errorMessage || 'Export failed');
513→        }
514→
515→        if (job.status === 'CANCELLED') {
516→            throw new Error('Export was cancelled');
517→        }
518→
519→        if (job.status === 'EXPIRED') {
520→            throw new Error('Export file has expired');
521→        }
522→
523→        // Wait before next poll
524→        await new Promise(resolve => setTimeout(resolve, pollInterval));
525→        polls++;
526→    }
527→
528→    throw new Error('Export timed out. Please try again.');
529→}
