 19→import React, { useState, useEffect } from 'react';
 20→import {
 21→    createException,
 22→    updateException,
 23→    getAssets,
 24→    previewExceptionImpact,
 25→    type VulnerabilityException,
 26→    type CreateExceptionRequest,
 27→    type UpdateExceptionRequest,
 28→    type Asset,
 29→    type ExceptionImpactPreview
 30→} from '../services/vulnerabilityManagementService';
 31→import ProductAutocomplete from './ProductAutocomplete';
 32→import ImpactPreviewModal from './ImpactPreviewModal';
 33→
 34→interface VulnerabilityExceptionFormProps {
 35→    exception?: VulnerabilityException;
 36→    onSave: () => void;
 37→    onCancel: () => void;
 38→}
 39→
 40→const VulnerabilityExceptionForm: React.FC<VulnerabilityExceptionFormProps> = ({
 41→    exception,
 42→    onSave,
 43→    onCancel
 44→}) => {
 45→    const [exceptionType, setExceptionType] = useState<string>(exception?.exceptionType || 'IP');
 46→    const [targetValue, setTargetValue] = useState<string>(exception?.targetValue || '');
 47→    const [selectedAssetId, setSelectedAssetId] = useState<number | null>(exception?.assetId || null);
 48→    const [cveScope, setCveScope] = useState<'all' | 'single'>('all');
 49→    const [expirationDate, setExpirationDate] = useState<string>(() => {
 50→        if (exception?.expirationDate) {
 51→            // Convert ISO string to datetime-local format
 52→            return exception.expirationDate.slice(0, 16);
 53→        }
 54→        // Default to 30 days from now
 55→        const future = new Date();
 56→        future.setDate(future.getDate() + 30);
 57→        return future.toISOString().slice(0, 16);
 58→    });
 59→    const [reason, setReason] = useState<string>(exception?.reason || '');
 60→    const [isSubmitting, setIsSubmitting] = useState(false);
 61→    const [error, setError] = useState<string | null>(null);
 62→    const [assets, setAssets] = useState<Asset[]>([]);
 63→    const [loadingAssets, setLoadingAssets] = useState(false);
 64→
 65→    // Phase 3: Impact preview state
 66→    const [showPreview, setShowPreview] = useState(false);
 67→    const [impactPreview, setImpactPreview] = useState<ExceptionImpactPreview | null>(null);
 68→    const [loadingPreview, setLoadingPreview] = useState(false);
 69→
 70→    const isEditMode = !!exception;
 71→
 72→    // Fetch assets when component mounts or when ASSET type is selected, or CVE with single scope
 73→    useEffect(() => {
 74→        if (exceptionType === 'ASSET' || (exceptionType === 'CVE' && cveScope === 'single')) {
 75→            fetchAssets();
 76→        }
 77→    }, [exceptionType, cveScope]);
 78→
 79→    const fetchAssets = async () => {
 80→        try {
 81→            setLoadingAssets(true);
 82→            const data = await getAssets();
 83→            setAssets(data);
 84→        } catch (err) {
 85→            console.error('Failed to fetch assets:', err);
 86→            setError('Failed to load assets. Please try again.');
 87→        } finally {
 88→            setLoadingAssets(false);
 89→        }
 90→    };
 91→
 92→    const validateIPAddress = (ip: string): boolean => {
 93→        const ipPattern = /^(\d{1,3}\.){3}\d{1,3}$/;
 94→        if (!ipPattern.test(ip)) return false;
 95→
 96→        const parts = ip.split('.');
 97→        return parts.every(part => {
 98→            const num = parseInt(part, 10);
 99→            return num >= 0 && num <= 255;
100→        });
101→    };
102→
103→    const validateCveId = (cve: string): boolean => {
104→        return /^CVE-\d{4}-\d+$/i.test(cve);
105→    };
106→
107→    const parseCveIds = (input: string): string[] => {
108→        return input.split(',').map(s => s.trim()).filter(s => s.length > 0);
109→    };
110→
111→    const validateForm = (): boolean => {
112→        if (exceptionType === 'ASSET') {
113→            if (!selectedAssetId) {
114→                setError('Please select an asset');
115→                return false;
116→            }
117→            // For ASSET type, targetValue should be the asset name
118→            const selectedAsset = assets.find(a => a.id === selectedAssetId);
119→            if (!selectedAsset) {
120→                setError('Selected asset not found');
121→                return false;
122→            }
123→        } else if (exceptionType === 'CVE') {
124→            if (!targetValue.trim()) {
125→                setError('At least one CVE ID is required');
126→                return false;
127→            }
128→            const cveIds = parseCveIds(targetValue);
129→            if (cveIds.length === 0) {
130→                setError('At least one CVE ID is required');
131→                return false;
132→            }
133→            for (const cveId of cveIds) {
134→                if (!validateCveId(cveId)) {
135→                    setError(`Invalid CVE ID format: '${cveId}'. Expected format: CVE-YYYY-NNNNN`);
136→                    return false;
137→                }
138→            }
139→            if (targetValue.trim().length > 512) {
140→                setError('CVE list exceeds maximum length of 512 characters');
141→                return false;
142→            }
143→            if (cveScope === 'single' && !selectedAssetId) {
144→                setError('Please select an asset for single-system scope');
145→                return false;
146→            }
147→        } else {
148→            if (!targetValue.trim()) {
149→                setError('Target value is required');
150→                return false;
151→            }
152→
153→            if (exceptionType === 'IP' && !validateIPAddress(targetValue)) {
154→                setError('Invalid IP address format');
155→                return false;
156→            }
157→        }
158→
159→        if (!expirationDate) {
160→            setError('Expiration date is required');
161→            return false;
162→        }
163→
164→        if (!reason.trim()) {
165→            setError('Reason is required');
166→            return false;
167→        }
168→
169→        return true;
170→    };
171→
172→    // Phase 3: Handle preview impact
173→    const handlePreviewImpact = async () => {
174→        setError(null);
175→
176→        // Basic validation before preview
177→        if (exceptionType === 'ASSET' && !selectedAssetId) {
178→            setError('Please select an asset');
179→            return;
180→        }
181→        if (exceptionType === 'CVE' && !targetValue.trim()) {
182→            setError('CVE ID is required');
183→            return;
184→        }
185→        if (exceptionType !== 'ASSET' && exceptionType !== 'CVE' && !targetValue.trim()) {
186→            setError('Target value is required');
187→            return;
188→        }
189→
190→        setLoadingPreview(true);
191→
192→        try {
193→            let previewAssetId: number | null = null;
194→            if (exceptionType === 'ASSET') {
195→                previewAssetId = selectedAssetId;
196→            } else if (exceptionType === 'CVE' && cveScope === 'single') {
197→                previewAssetId = selectedAssetId;
198→            }
199→
200→            const preview = await previewExceptionImpact({
201→                exceptionType,
202→                targetValue: targetValue.trim(),
203→                assetId: previewAssetId
204→            });
205→
206→            setImpactPreview(preview);
207→            setShowPreview(true);
208→        } catch (err) {
209→            setError(err instanceof Error ? err.message : 'Failed to preview impact');
210→        } finally {
211→            setLoadingPreview(false);
212→        }
213→    };
214→
215→    // Phase 3: Create exception after preview confirmation
216→    const handleConfirmAndCreate = async () => {
217→        if (!validateForm()) {
218→            setShowPreview(false);
219→            return;
220→        }
221→
222→        setIsSubmitting(true);
223→
224→        try {
225→            // Create new exception
226→            let finalTargetValue = targetValue.trim();
227→            let finalAssetId = null;
228→
229→            if (exceptionType === 'ASSET') {
230→                const selectedAsset = assets.find(a => a.id === selectedAssetId);
231→                if (selectedAsset) {
232→                    finalTargetValue = selectedAsset.name;
233→                    finalAssetId = selectedAsset.id;
234→                }
235→            } else if (exceptionType === 'CVE') {
236→                if (cveScope === 'single' && selectedAssetId) {
237→                    finalAssetId = selectedAssetId;
238→                }
239→            }
240→
241→            const request: CreateExceptionRequest = {
242→                exceptionType,
243→                targetValue: finalTargetValue,
244→                expirationDate: new Date(expirationDate).toISOString(),
245→                reason: reason.trim(),
246→                assetId: finalAssetId
247→            };
248→            await createException(request);
249→
250→            setShowPreview(false);
251→            onSave();
252→        } catch (err) {
253→            setError(err instanceof Error ? err.message : 'Failed to save exception');
254→            setShowPreview(false);
255→        } finally {
256→            setIsSubmitting(false);
257→        }
258→    };
259→
260→    const handleSubmit = async (e: React.FormEvent) => {
261→        e.preventDefault();
262→        setError(null);
263→
264→        if (!validateForm()) {
265→            return;
266→        }
267→
268→        // Phase 3: For new exceptions, show preview first
269→        if (!isEditMode) {
270→            await handlePreviewImpact();
271→            return;
272→        }
273→
274→        // For edit mode, proceed directly
275→        setIsSubmitting(true);
276→
277→        try {
278→            // Update existing exception
279→            const request: UpdateExceptionRequest = {
280→                expirationDate: new Date(expirationDate).toISOString(),
281→                reason: reason.trim()
282→            };
283→            await updateException(exception.id, request);
284→
285→            onSave();
286→        } catch (err) {
287→            setError(err instanceof Error ? err.message : 'Failed to save exception');
288→        } finally {
289→            setIsSubmitting(false);
290→        }
291→    };
292→
293→    const handleTypeChange = (newType: string) => {
294→        setExceptionType(newType);
295→        setTargetValue('');
296→        setSelectedAssetId(null);
297→        setCveScope('all');
298→        setError(null);
299→    };
300→
301→
302→    return (
303→        <>
304→        <form onSubmit={handleSubmit}>
305→            {error && (
306→                <div className="alert alert-danger alert-dismissible fade show" role="alert">
307→                    <i className="bi bi-exclamation-triangle me-2"></i>
308→                    {error}
309→                    <button type="button" className="btn-close" onClick={() => setError(null)} aria-label="Close"></button>
310→                </div>
311→            )}
312→
313→            {/* Exception Type (only for new exceptions) */}
314→            {!isEditMode && (
315→                <div className="mb-4">
316→                    <label className="form-label fw-bold">
317→                        Exception Type *
318→                        <i 
319→                            className="bi bi-question-circle ms-2 text-muted" 
320→                            data-bs-toggle="tooltip" 
321→                            title="Choose how to target this exception"
322→                            style={{ cursor: 'help', fontSize: '0.875rem' }}
323→                        ></i>
324→                    </label>
325→                    <div className="d-flex gap-4">
326→                        <div className="form-check">
327→                            <input
328→                                className="form-check-input"
329→                                type="radio"
330→                                name="exceptionType"
331→                                id="typeIP"
332→                                value="IP"
333→                                checked={exceptionType === 'IP'}
334→                                onChange={(e) => handleTypeChange(e.target.value)}
335→                                disabled={isSubmitting}
336→                            />
337→                            <label className="form-check-label" htmlFor="typeIP">
338→                                <strong>IP Address</strong>
339→                                <br />
340→                                <small className="text-muted">All vulnerabilities on this IP</small>
341→                            </label>
342→                        </div>
343→                        <div className="form-check">
344→                            <input
345→                                className="form-check-input"
346→                                type="radio"
347→                                name="exceptionType"
348→                                id="typePRODUCT"
349→                                value="PRODUCT"
350→                                checked={exceptionType === 'PRODUCT'}
351→                                onChange={(e) => handleTypeChange(e.target.value)}
352→                                disabled={isSubmitting}
353→                            />
354→                            <label className="form-check-label" htmlFor="typePRODUCT">
355→                                <strong>Product</strong>
356→                                <br />
357→                                <small className="text-muted">Vulnerabilities matching product name</small>
358→                            </label>
359→                        </div>
360→                        <div className="form-check">
361→                            <input
362→                                className="form-check-input"
363→                                type="radio"
364→                                name="exceptionType"
365→                                id="typeASSET"
366→                                value="ASSET"
367→                                checked={exceptionType === 'ASSET'}
368→                                onChange={(e) => handleTypeChange(e.target.value)}
369→                                disabled={isSubmitting}
370→                            />
371→                            <label className="form-check-label" htmlFor="typeASSET">
372→                                <strong>Asset</strong>
373→                                <br />
374→                                <small className="text-muted">All vulnerabilities on specific asset</small>
375→                            </label>
376→                        </div>
377→                        <div className="form-check">
378→                            <input
379→                                className="form-check-input"
380→                                type="radio"
381→                                name="exceptionType"
382→                                id="typeCVE"
383→                                value="CVE"
384→                                checked={exceptionType === 'CVE'}
385→                                onChange={(e) => handleTypeChange(e.target.value)}
386→                                disabled={isSubmitting}
387→                            />
388→                            <label className="form-check-label" htmlFor="typeCVE">
389→                                <strong>CVE</strong>
390→                                <br />
391→                                <small className="text-muted">Exception for a specific CVE ID</small>
392→                            </label>
393→                        </div>
394→                    </div>
395→                    <div className="alert alert-info mt-3 mb-0" role="alert">
396→                        <small>
397→                            <i className="bi bi-lightbulb me-2"></i>
398→                            {exceptionType === 'IP' && 'IP exceptions apply to all vulnerabilities on the specified IP address.'}
399→                            {exceptionType === 'PRODUCT' && 'Product exceptions apply to all vulnerabilities matching the product name/version.'}
400→                            {exceptionType === 'ASSET' && 'Asset exceptions apply to all vulnerabilities on the specific asset, even if its IP changes.'}
401→                            {exceptionType === 'CVE' && 'CVE exceptions apply to all vulnerabilities matching the CVE ID(s). You can enter multiple comma-separated CVEs, optionally scoped to a single system.'}
402→                        </small>
403→                    </div>
404→                </div>
405→            )}
406→
407→            {/* Conditional Forms Based on Type */}
408→            {!isEditMode && (
409→                <>
410→                    {/* Asset Selector for ASSET type */}
411→                    {exceptionType === 'ASSET' && (
412→                        <div className="mb-3">
413→                            <label htmlFor="assetSelect" className="form-label">
414→                                Select Asset *
415→                            </label>
416→                            {loadingAssets ? (
417→                                <div className="text-center py-3">
418→                                    <div className="spinner-border spinner-border-sm" role="status">
419→                                        <span className="visually-hidden">Loading assets...</span>
420→                                    </div>
421→                                    <span className="ms-2">Loading assets...</span>
422→                                </div>
423→                            ) : (
424→                                <select
425→                                    className="form-select"
426→                                    id="assetSelect"
427→                                    value={selectedAssetId || ''}
428→                                    onChange={(e) => setSelectedAssetId(Number(e.target.value) || null)}
429→                                    disabled={isSubmitting}
430→                                    required
431→                                >
432→                                    <option value="">-- Select an asset --</option>
433→                                    {assets.map(asset => (
434→                                        <option key={asset.id} value={asset.id}>
435→                                            {asset.name} {asset.ip ? `(${asset.ip})` : ''}
436→                                        </option>
437→                                    ))}
438→                                </select>
439→                            )}
440→                            <small className="form-text text-muted">
441→                                {assets.length} asset(s) available. Exception will apply to all vulnerabilities on this asset.
442→                            </small>
443→                        </div>
444→                    )}
445→
446→                    {/* IP Input for IP type */}
447→                    {exceptionType === 'IP' && (
448→                        <div className="mb-3">
449→                            <label htmlFor="targetValue" className="form-label">
450→                                IP Address *
451→                            </label>
452→                            <input
453→                                type="text"
454→                                className="form-control"
455→                                id="targetValue"
456→                                value={targetValue}
457→                                onChange={(e) => setTargetValue(e.target.value)}
458→                                placeholder="e.g., 192.168.1.100"
459→                                disabled={isSubmitting}
460→                                required
461→                            />
462→                            <small className="form-text text-muted">
463→                                Enter a valid IPv4 address (e.g., 10.0.0.1)
464→                            </small>
465→                        </div>
466→                    )}
467→
468→                    {/* Product Input for PRODUCT type - Phase 3: Now with autocomplete */}
469→                    {exceptionType === 'PRODUCT' && (
470→                        <div className="mb-3">
471→                            <label htmlFor="targetValue" className="form-label">
472→                                Product Name/Version *
473→                                <i
474→                                    className="bi bi-question-circle ms-2 text-muted"
475→                                    data-bs-toggle="tooltip"
476→                                    title="Start typing to see suggestions from existing vulnerabilities"
477→                                    style={{ cursor: 'help', fontSize: '0.875rem' }}
478→                                ></i>
479→                            </label>
480→                            <ProductAutocomplete
481→                                value={targetValue}
482→                                onChange={setTargetValue}
483→                                placeholder="e.g., Apache HTTP Server 2.4.41"
484→                                disabled={isSubmitting}
485→                            />
486→                            <small className="form-text text-muted">
487→                                Product name or version - partial matches supported. Select from suggestions or enter custom value.
488→                            </small>
489→                        </div>
490→                    )}
491→
492→                    {/* CVE Input for CVE type */}
493→                    {exceptionType === 'CVE' && (
494→                        <>
495→                            <div className="mb-3">
496→                                <label htmlFor="cveTargetValue" className="form-label">
497→                                    CVE ID(s) *
498→                                </label>
499→                                <textarea
500→                                    className="form-control"
501→                                    id="cveTargetValue"
502→                                    rows={3}
503→                                    value={targetValue}
504→                                    onChange={(e) => setTargetValue(e.target.value)}
505→                                    placeholder="CVE-2023-29326, CVE-2024-1234, CVE-2024-5678"
506→                                    disabled={isSubmitting}
507→                                    required
508→                                    maxLength={512}
509→                                />
510→                                <small className="form-text text-muted">
511→                                    Enter one or more CVE identifiers, separated by commas. {targetValue.length}/512 characters
512→                                </small>
513→                            </div>
514→
515→                            <div className="mb-3">
516→                                <label className="form-label fw-bold">Scope</label>
517→                                <div className="d-flex gap-4">
518→                                    <div className="form-check">
519→                                        <input
520→                                            className="form-check-input"
521→                                            type="radio"
522→                                            name="cveScope"
523→                                            id="cveScopeAll"
524→                                            checked={cveScope === 'all'}
525→                                            onChange={() => { setCveScope('all'); setSelectedAssetId(null); }}
526→                                            disabled={isSubmitting}
527→                                        />
528→                                        <label className="form-check-label" htmlFor="cveScopeAll">
529→                                            <strong>All systems</strong>
530→                                            <br />
531→                                            <small className="text-muted">Exception applies system-wide</small>
532→                                        </label>
533→                                    </div>
534→                                    <div className="form-check">
535→                                        <input
536→                                            className="form-check-input"
537→                                            type="radio"
538→                                            name="cveScope"
539→                                            id="cveScopeSingle"
540→                                            checked={cveScope === 'single'}
541→                                            onChange={() => setCveScope('single')}
542→                                            disabled={isSubmitting}
543→                                        />
544→                                        <label className="form-check-label" htmlFor="cveScopeSingle">
545→                                            <strong>Specific system</strong>
546→                                            <br />
547→                                            <small className="text-muted">Exception applies to one asset only</small>
548→                                        </label>
549→                                    </div>
550→                                </div>
551→                            </div>
552→
553→                            {cveScope === 'single' && (
554→                                <div className="mb-3">
555→                                    <label htmlFor="cveAssetSelect" className="form-label">
556→                                        Select Asset *
557→                                    </label>
558→                                    {loadingAssets ? (
559→                                        <div className="text-center py-3">
560→                                            <div className="spinner-border spinner-border-sm" role="status">
561→                                                <span className="visually-hidden">Loading assets...</span>
562→                                            </div>
563→                                            <span className="ms-2">Loading assets...</span>
564→                                        </div>
565→                                    ) : (
566→                                        <select
567→                                            className="form-select"
568→                                            id="cveAssetSelect"
569→                                            value={selectedAssetId || ''}
570→                                            onChange={(e) => setSelectedAssetId(Number(e.target.value) || null)}
571→                                            disabled={isSubmitting}
572→                                            required
573→                                        >
574→                                            <option value="">-- Select an asset --</option>
575→                                            {assets.map(asset => (
576→                                                <option key={asset.id} value={asset.id}>
577→                                                    {asset.name} {asset.ip ? `(${asset.ip})` : ''}
578→                                                </option>
579→                                            ))}
580→                                        </select>
581→                                    )}
582→                                    <small className="form-text text-muted">
583→                                        {assets.length} asset(s) available. Exception will only apply to this CVE on the selected asset.
584→                                    </small>
585→                                </div>
586→                            )}
587→                        </>
588→                    )}
589→                </>
590→            )}
591→
592→            {/* Expiration Date */}
593→            <div className="mb-3">
594→                <label htmlFor="expirationDate" className="form-label">
595→                    Expiration Date *
596→                    <i 
597→                        className="bi bi-question-circle ms-2 text-muted" 
598→                        data-bs-toggle="tooltip" 
599→                        title="All exceptions require an end date for periodic review"
600→                        style={{ cursor: 'help', fontSize: '0.875rem' }}
601→                    ></i>
602→                </label>
603→                <input
604→                    type="datetime-local"
605→                    className="form-control"
606→                    id="expirationDate"
607→                    value={expirationDate}
608→                    onChange={(e) => setExpirationDate(e.target.value)}
609→                    disabled={isSubmitting}
610→                    required
611→                />
612→                <small className="form-text text-muted">
613→                    When should this exception expire? Default is 30 days from now.
614→                </small>
615→            </div>
616→
617→            {/* Reason */}
618→            <div className="mb-3">
619→                <label htmlFor="reason" className="form-label">
620→                    Justification / Reason *
621→                </label>
622→                <textarea
623→                    className="form-control"
624→                    id="reason"
625→                    rows={4}
626→                    value={reason}
627→                    onChange={(e) => setReason(e.target.value)}
628→                    placeholder="Explain why this exception is needed (e.g., planned maintenance, false positive, accepted risk)..."
629→                    disabled={isSubmitting}
630→                    required
631→                    maxLength={1024}
632→                />
633→                <small className="form-text text-muted">
634→                    {reason.length}/1024 characters
635→                </small>
636→            </div>
637→
638→            {/* Form Actions */}
639→            <div className="d-flex justify-content-end gap-2 mt-4">
640→                <button
641→                    type="button"
642→                    className="btn btn-secondary"
643→                    onClick={onCancel}
644→                    disabled={isSubmitting}
645→                >
646→                    <i className="bi bi-x-lg me-2"></i>
647→                    Cancel
648→                </button>
649→                <button
650→                    type="submit"
651→                    className="btn btn-primary"
652→                                    disabled={isSubmitting || ((exceptionType === 'ASSET' || (exceptionType === 'CVE' && cveScope === 'single')) && loadingAssets) || loadingPreview}
653→                >
654→                    {loadingPreview ? (
655→                        <>
656→                            <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
657→                            Loading preview...
658→                        </>
659→                    ) : isSubmitting ? (
660→                        <>
661→                            <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
662→                            {isEditMode ? 'Updating...' : 'Creating...'}
663→                        </>
664→                    ) : (
665→                        <>
666→                            <i className={`bi ${isEditMode ? 'bi-check-lg' : 'bi-eye'} me-2`}></i>
667→                            {isEditMode ? 'Update Exception' : 'Preview & Create'}
668→                        </>
669→                    )}
670→                </button>
671→            </div>
672→        </form>
673→
674→        {/* Phase 3: Impact Preview Modal */}
675→        {!isEditMode && impactPreview && (
676→            <ImpactPreviewModal
677→                show={showPreview}
678→                onClose={() => setShowPreview(false)}
679→                onConfirm={handleConfirmAndCreate}
680→                exceptionType={exceptionType}
681→                targetValue={targetValue}
682→                totalCount={impactPreview.totalCount}
683→                sampleSize={impactPreview.sampleSize}
684→                countBySeverity={impactPreview.countBySeverity}
685→                isSubmitting={isSubmitting}
686→            />
687→        )}
688→    </>
689→    );
690→};
691→
692→export default VulnerabilityExceptionForm;
